import{_ as a,o as e,c as l,ag as s}from"./chunks/framework.BZohXCq9.js";const k=JSON.parse('{"title":"App 组合根","description":"","frontmatter":{},"headers":[],"relativePath":"app.md","filePath":"app.md","lastUpdated":1775494190000}'),t={name:"app.md"};function p(d,i,o,n,r,h){return e(),l("div",null,[...i[0]||(i[0]=[s(`<h1 id="app-组合根" tabindex="-1">App 组合根 <a class="header-anchor" href="#app-组合根" aria-label="Permalink to &quot;App 组合根&quot;">​</a></h1><p>App 层负责把已经存在的 SDK、Core、UI 和 bridge 装配成真正可启动的宿主程序。它的职责不是重新定义协议，而是把现有能力组合成最终入口。</p><p>在 <code>0.2.0</code> 中，宿主入口在实现上仍然分成三条，但对外公开分发统一收口到 <code>modlink-studio</code> 一个主包：</p><ul><li><code>modlink_studio</code>：主桌面宿主，使用 <code>modlink_ui_qt_widgets</code></li><li><code>modlink_studio_qml</code>：QML 宿主，使用 <code>modlink_ui_qt_qml</code></li><li><code>modlink_server</code>：FastAPI 服务宿主，为后续 HTML / Web UI 准备</li></ul><h2 id="这页主要回答什么" tabindex="-1">这页主要回答什么 <a class="header-anchor" href="#这页主要回答什么" aria-label="Permalink to &quot;这页主要回答什么&quot;">​</a></h2><ol><li>最终用户从哪里启动宿主</li><li>App 层启动时会创建哪些对象</li><li>已安装的 driver 是怎么被发现的</li><li>App 层保留了哪些 fail-fast 边界</li></ol><h2 id="启动入口" tabindex="-1">启动入口 <a class="header-anchor" href="#启动入口" aria-label="Permalink to &quot;启动入口&quot;">​</a></h2><p>正式安装方式见 <a href="/install">安装与发布</a>。<code>0.2.0</code> 的主桌面宿主入口是：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">modlink-studio</span></span></code></pre></div><p>调试入口保留为：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> modlink_studio</span></span></code></pre></div><p>如果要直接联调 QML 宿主：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">modlink-studio-qml</span></span></code></pre></div><p>或：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> modlink_studio_qml</span></span></code></pre></div><p><code>modlink_server</code> 当前主要面向前端联调和宿主边界验证，而不是普通终端用户的默认入口。</p><p>这三个入口在 <code>0.2.x-0.3.x</code> 阶段都会由同一个 <code>modlink-studio</code> distribution 提供，而不是拆成多个公开 PyPI 包。</p><h2 id="app-层到底负责什么" tabindex="-1">App 层到底负责什么 <a class="header-anchor" href="#app-层到底负责什么" aria-label="Permalink to &quot;App 层到底负责什么&quot;">​</a></h2><p>以桌面宿主为例，App 层当前会做这些事：</p><ol><li>创建或复用 <code>QApplication</code></li><li>设置应用名、图标和主题</li><li>初始化设置服务</li><li>发现当前环境里的 driver factories</li><li>创建 <code>ModLinkEngine</code></li><li>创建主窗口或 QML window</li><li>把 Qt 的 <code>aboutToQuit</code> 接到 runtime shutdown</li><li>启动 Qt 事件循环</li></ol><p>这层的核心特征是“装配”，而不是“定义新协议”。</p><h2 id="一个启动流程大概长什么样" tabindex="-1">一个启动流程大概长什么样 <a class="header-anchor" href="#一个启动流程大概长什么样" aria-label="Permalink to &quot;一个启动流程大概长什么样&quot;">​</a></h2><p>从当前实现看，宿主启动顺序大致是：</p><ol><li>创建应用对象</li><li>初始化主题、图标和设置</li><li>扫描 <code>modlink.drivers</code></li><li>用扫描到的 driver factories 创建 <code>ModLinkEngine</code></li><li>创建对应宿主窗口或 controller</li><li>进入事件循环</li></ol><p>这条顺序说明：</p><ul><li>driver 发现发生在应用启动阶段</li><li>Core 运行时在窗口创建前就已经准备好</li><li>UI 页面拿到的是已经组装好的 engine，而不是自己去拼 driver 或流总线</li></ul><h2 id="插件发现模型" tabindex="-1">插件发现模型 <a class="header-anchor" href="#插件发现模型" aria-label="Permalink to &quot;插件发现模型&quot;">​</a></h2><p>宿主不会在运行时临时发现“未安装的插件”。当前模型是“先安装，再发现”：</p><ul><li>插件通过 <code>modlink-plugin install ...</code> 安装到当前环境</li><li>外部 driver 在当前阶段主要通过源码环境和本地安装联调到同一个 Python 环境</li><li>宿主启动时扫描当前环境里的 <code>modlink.drivers</code></li></ul><p>一个外部 driver 的典型联调方式是：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ../my_driver</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> modlink_studio</span></span></code></pre></div><p>这意味着：</p><ul><li>App 层只负责发现已经安装好的 driver</li><li>driver 的安装和版本管理发生在 Python 包环境层，而不是宿主界面层</li></ul><h2 id="为什么外部-driver-不依赖宿主应用" tabindex="-1">为什么外部 driver 不依赖宿主应用 <a class="header-anchor" href="#为什么外部-driver-不依赖宿主应用" aria-label="Permalink to &quot;为什么外部 driver 不依赖宿主应用&quot;">​</a></h2><p><code>modlink-studio</code> 是最终桌面宿主，不是 driver 的最小公共接口。</p><p>外部 driver 更合理的依赖边界是：</p><ul><li>SDK 契约当前仍在仓库内明确存在</li><li>只有确实需要运行时服务时，才额外依赖 <code>modlink-core</code></li></ul><p>这样可以让 driver 依赖最小稳定接口，而不是反向绑死在整个宿主应用上。</p><h2 id="app-层保留的-fail-fast-边界" tabindex="-1">App 层保留的 fail-fast 边界 <a class="header-anchor" href="#app-层保留的-fail-fast-边界" aria-label="Permalink to &quot;App 层保留的 fail-fast 边界&quot;">​</a></h2><p>App 层当前明确保留 fail-fast 策略：</p><ul><li>损坏的 driver entry point 会在启动或加载阶段直接暴露错误</li><li>未知 payload 类型不会在 App 层被静默吞掉</li><li>明显的插件协议错误会尽早暴露，而不是拖到运行过程中再变成更难排查的问题</li></ul><p>这里的判断很明确：driver 是系统核心组成，不是可有可无的附属插件。</p><h2 id="仓库内联调" tabindex="-1">仓库内联调 <a class="header-anchor" href="#仓库内联调" aria-label="Permalink to &quot;仓库内联调&quot;">​</a></h2><p>官方驱动源码已经迁移到独立仓库 <code>ModLink-Studio-Plugins</code>。当前主仓库的宿主应用只负责发现已经安装进环境的插件；如果需要联调官方驱动源码，请在插件仓库中完成构建、发布或本地安装，再回到当前宿主环境验证。</p><p>如果目的是理解 driver 契约，优先继续看 <a href="/sdk">SDK</a>。如果目的是理解 runtime 如何托管 driver 和流，继续看 <a href="/core">Core</a>。如果目的是联调 Web / HTML 前端，则直接看 <a href="/server-api">服务端 API 手册</a>。</p>`,45)])])}const u=a(t,[["render",p]]);export{k as __pageData,u as default};
